    30→absl::StatusOr<absl::optional<CBS>> Asn1Utility::getOptional(CBS& cbs, unsigned tag) {
    31→  int is_present;
    32→  CBS data;
    33→  if (!CBS_get_optional_asn1(&cbs, &data, &is_present, tag)) {
    34→    return absl::InvalidArgumentError("Failed to parse ASN.1 element tag");
    35→  }
    36→
    37→  return is_present ? absl::optional<CBS>(data) : absl::nullopt;
