    41→  CBS oid;
    42→  if (!CBS_get_asn1(&cbs, &oid, CBS_ASN1_OBJECT)) {
    43→    return absl::InvalidArgumentError("Input is not a well-formed ASN.1 OBJECT");
    44→  }
    45→  CSmartPtr<char, freeOpensslString> oid_text(CBS_asn1_oid_to_text(&oid));
