    55→  CBS elem;
    56→  if (!CBS_get_asn1(&cbs, &elem, CBS_ASN1_GENERALIZEDTIME)) {
    57→    return absl::InvalidArgumentError("Input is not a well-formed ASN.1 GENERALIZEDTIME");
    58→  }
